// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{})
}

type ChiServerOptions struct {
	BaseURL          string
	BaseRouter       chi.Router
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, r chi.Router) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseRouter: r,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, r chi.Router, baseURL string) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseURL:    baseURL,
		BaseRouter: r,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options ChiServerOptions) http.Handler {
	r := options.BaseRouter

	if r == nil {
		r = chi.NewRouter()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}
	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/audit-logs", wrapper.ListAuditLogs)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/auth/login", wrapper.Login)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/auth/logout", wrapper.Logout)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/auth/me", wrapper.GetMe)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/auth/password-reset", wrapper.ResetPassword)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/auth/password-reset-request", wrapper.RequestPasswordReset)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/auth/refresh", wrapper.RefreshToken)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/brands", wrapper.ListBrands)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/brands", wrapper.CreateBrand)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/brands/{brandID}", wrapper.DeleteBrand)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/brands/{brandID}", wrapper.GetBrand)
	})
	r.Group(func(r chi.Router) {
		r.Put(options.BaseURL+"/brands/{brandID}", wrapper.UpdateBrand)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/brands/{brandID}/managers", wrapper.AssignManager)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/brands/{brandID}/managers/{userID}", wrapper.RemoveManager)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/creators/applications", wrapper.SubmitCreatorApplication)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/creators/applications/counts", wrapper.GetCreatorApplicationsCounts)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/creators/applications/list", wrapper.ListCreatorApplications)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/creators/applications/{id}", wrapper.GetCreatorApplication)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/dictionaries/{type}", wrapper.ListDictionary)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/healthz", wrapper.HealthCheck)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/webhooks/sendpulse/instagram", wrapper.SendPulseInstagramWebhook)
	})

	return r
}

